import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'

const BigImageSection = styled.div `
width:86%;
height:600px;
margin:30px auto;
display:flex;
justify-content:space-between;
`


const BigImageWrapper = styled.div `
width:600px;
height:500px;
background-image:url('https://res.cloudinary.com/ssenseweb/image/upload/w_1280,q_90,f_auto,dpr_auto/v1668434286/maiqdcmzqyxvoc8rpfvx.jpg');
background-size:cover;
background-position:center;

`

const Footer = styled.div `
width:100%;
height:180px;
background-color:white;
font-size:1rem;
padding-top:10px;
`

const Title = styled.div `
font-weight:900;
`

const Content = styled.div `
overflow:hidden;
white-space: nowrap;
text-overflow: ellipsis;
`

export default function Articles () {
	return (
		<>
		<Header/>
		<Navbar/>
		<BigImageSection>
			<div>
				<BigImageWrapper />
				<Footer>
					<Title>Community Craftsmanship: Acne Studios Repurposed FW22</Title>
					<Content>FIVE NEW YORK–BASED ARTISTS TRY OUT THE SSENSE EXCLUSIVE COLLECTION</Content>
				</Footer>
			</div>
			<div>
				<BigImageWrapper />
				<Footer/>
			</div>
		</BigImageSection>
		</>

	)
}
